---
import BaseLayout from './BaseLayout.astro';

interface Props {
  title: string;
  description: string;
}

const { title, description } = Astro.props;
---

<BaseLayout title={`${title} — Scientific Agentic Engineering`} description={description}>
  <article class="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-12 prose prose-gray">
    <slot />
  </article>
</BaseLayout>

---
import FrameworkLayout from '../../layouts/FrameworkLayout.astro';
import { getCollection, render } from 'astro:content';

export async function getStaticPaths() {
  const entries = await getCollection('framework');
  return entries.map(entry => ({
    params: { slug: entry.id },
    props: { entry },
  }));
}

const { entry } = Astro.props;
const { Content } = await render(entry);
---

<FrameworkLayout title={entry.data.title} description={entry.data.description}>
  <Content />
</FrameworkLayout>

